import {useMemo} from 'react';
import {useKitsTheme} from '../contexts/Theme';
import type {IStyleClasses} from '@lmb-it/kitsconcerto-types';

/**
 * Derives color-related style props from a colorScheme name and optional variant.
 * Returns CSS prop overrides that can be spread into cssProps.
 *
 * @example
 * const colorStyles = useKitsColorScheme('blue', 'solid');
 * // colorStyles = { bgColor: 'blue.500', fontColor: 'white' }
 */
export default function useKitsColorScheme(
    colorScheme: string | undefined,
    variant?: 'solid' | 'subtle' | 'outline' | 'ghost',
): Partial<IStyleClasses> {
    const {resolveToken, colorMode} = useKitsTheme();

    return useMemo(() => {
        if (!colorScheme) return {};

        const isDark = colorMode === 'dark';
        const baseShade = isDark ? '200' : '500';
        const hoverShade = isDark ? '300' : '600';
        const subtleBg = isDark ? '800' : '100';
        const subtleText = isDark ? '200' : '700';

        switch (variant) {
            case 'subtle':
            case 'ghost':
                return {
                    bgColor: resolveToken(`${colorScheme}.${subtleBg}`),
                    fontColor: resolveToken(`${colorScheme}.${subtleText}`),
                } as Partial<IStyleClasses>;

            case 'outline':
                return {
                    borderColor: resolveToken(`${colorScheme}.${baseShade}`),
                    fontColor: resolveToken(`${colorScheme}.${baseShade}`),
                    borderWidth: '1px',
                    borderStyle: 'solid',
                } as Partial<IStyleClasses>;

            default: // 'solid' or undefined
                return {
                    bgColor: resolveToken(`${colorScheme}.${baseShade}`),
                    fontColor: '#FFFFFF',
                } as Partial<IStyleClasses>;
        }
    }, [colorScheme, variant, resolveToken, colorMode]);
}
